import React, { useState } from 'react';

interface Photo {
  id: number;
  emoji: string;
  caption: string;
  color: string;
  label: string;
  image: string; // Optional, can be used for real photos in the future
}

const photos: Photo[] = [
  { id: 1, emoji: '💍', caption: 'Ring Ceremony', color: 'from-rose-900 to-red-950', label: 'The Promise' },
  { id: 2, emoji: '🌺', caption: 'Mehendi Night', color: 'from-emerald-900 to-green-950', label: 'Henna Night' },
  { id: 3, emoji: '🎊', caption: 'Haldi Ceremony', color: 'from-yellow-800 to-amber-950', label: 'Turmeric Glow' },
  { id: 4, emoji: '🪔', caption: 'Temple Blessing', color: 'from-orange-900 to-red-950', label: 'Sacred Moments' },
  { id: 5, emoji: '👗', caption: 'Bridal Look', color: 'from-pink-900 to-rose-950', label: 'The Bride' },
];

const PhotoGallery: React.FC = () => {
  const [lightbox, setLightbox] = useState<Photo | null>(null);

  return (
    <section
      id="gallery"
      style={{
        minHeight: '100vh',
        background: 'linear-gradient(180deg, #050205 0%, #1a0508 30%, #2a0810 60%, #1a0508 80%, #050205 100%)',
        padding: '80px 20px',
        position: 'relative',
        overflow: 'hidden',
      }}
    >
      {/* Background pattern */}
      <div
        style={{
          position: 'absolute',
          inset: 0,
          backgroundImage: `radial-gradient(circle at 20% 50%, rgba(180,30,0,0.08) 0%, transparent 50%),
                            radial-gradient(circle at 80% 20%, rgba(255,107,53,0.06) 0%, transparent 40%)`,
          pointerEvents: 'none',
        }}
      />

      <div style={{ maxWidth: 1100, margin: '0 auto', position: 'relative' }}>
        {/* Title */}
        <div style={{ textAlign: 'center', marginBottom: 60 }}>
          <div
            style={{
              fontFamily: "'Noto Serif Tamil', serif",
              fontSize: 12,
              color: '#FFA07A',
              letterSpacing: '0.3em',
              marginBottom: 8,
            }}
          >
            நினைவுகள்
          </div>
          <h2
            style={{
              fontFamily: "'Cormorant Garamond', serif",
              fontSize: 'clamp(2rem, 6vw, 3.5rem)',
              color: '#FFD700',
              fontStyle: 'italic',
              fontWeight: 300,
              margin: '0 0 16px',
              letterSpacing: '0.05em',
            }}
          >
            Our Gallery
          </h2>
          <div style={{ display: 'flex', alignItems: 'center', gap: 16, justifyContent: 'center' }}>
            <div style={{ flex: 1, maxWidth: 120, height: 1, background: 'linear-gradient(90deg, transparent, #FFD700)' }} />
            <span style={{ color: '#FFD700', fontSize: 18 }}>✦</span>
            <div style={{ flex: 1, maxWidth: 120, height: 1, background: 'linear-gradient(90deg, #FFD700, transparent)' }} />
          </div>
        </div>

        {/* Gallery grid (first 5 photos) */}
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fill, minmax(min(280px, 100%), 1fr))',
            gap: 20,
          }}
        >
          {photos.map((photo, idx) => (
            <div
              key={photo.id}
              onClick={() => setLightbox(photo)}
              style={{
                aspectRatio: '4/3',
                background: getColor(photo.color),
                border: '1px solid rgba(255,215,0,0.2)',
                borderRadius: 8,
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                justifyContent: 'center',
                cursor: 'pointer',
                position: 'relative',
                overflow: 'hidden',
                transition: 'all 0.3s ease',
                boxShadow: '0 4px 20px rgba(0,0,0,0.4)',
              }}
              onMouseEnter={(e) => {
                (e.currentTarget as HTMLElement).style.transform = 'translateY(-6px) scale(1.02)';
                (e.currentTarget as HTMLElement).style.border = '1px solid rgba(255,215,0,0.6)';
                (e.currentTarget as HTMLElement).style.boxShadow = '0 12px 40px rgba(255,107,53,0.3)';
              }}
              onMouseLeave={(e) => {
                (e.currentTarget as HTMLElement).style.transform = 'translateY(0) scale(1)';
                (e.currentTarget as HTMLElement).style.border = '1px solid rgba(255,215,0,0.2)';
                (e.currentTarget as HTMLElement).style.boxShadow = '0 4px 20px rgba(0,0,0,0.4)';
              }}
            >
              {/* Gradient overlay */}
              <div
                style={{
                  position: 'absolute',
                  inset: 0,
                  background: 'linear-gradient(180deg, transparent 40%, rgba(0,0,0,0.7) 100%)',
                }}
              />

              {/* Emoji */}
              <div style={{ fontSize: 48, marginBottom: 12, filter: 'drop-shadow(0 4px 8px rgba(0,0,0,0.5))' }}>
                {photo.emoji}
              </div>

              {/* Bottom label */}
              <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, padding: '12px 16px' }}>
                <div
                  style={{
                    fontFamily: "'Cormorant Garamond', serif",
                    fontSize: 'clamp(1rem, 2.5vw, 1.3rem)',
                    color: '#FFD700',
                    fontStyle: 'italic',
                    fontWeight: 400,
                  }}
                >
                  {photo.label}
                </div>
                <div
                  style={{
                    fontFamily: "'Cormorant Garamond', serif",
                    fontSize: 11,
                    color: 'rgba(255,160,122,0.8)',
                    letterSpacing: '0.2em',
                  }}
                >
                  {photo.caption.toUpperCase()}
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Lightbox */}
      {lightbox && (
        <div
          onClick={() => setLightbox(null)}
          style={{
            position: 'fixed',
            inset: 0,
            background: 'rgba(0,0,0,0.92)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 9998,
            backdropFilter: 'blur(8px)',
            animation: 'fadeIn 0.3s ease',
          }}
        >
          <div
            style={{
              background: getColor(lightbox.color),
              border: '1.5px solid rgba(255,215,0,0.4)',
              borderRadius: 12,
              padding: '60px 80px',
              textAlign: 'center',
              maxWidth: 500,
              width: '90vw',
              boxShadow: '0 0 80px rgba(255,107,53,0.3)',
              animation: 'scaleIn 0.3s ease',
            }}
          >
            <div style={{ fontSize: 80, marginBottom: 24 }}>{lightbox.emoji}</div>
            <div
              style={{
                fontFamily: "'Cormorant Garamond', serif",
                fontSize: '2.5rem',
                color: '#FFD700',
                fontStyle: 'italic',
                marginBottom: 8,
              }}
            >
              {lightbox.label}
            </div>
            <div
              style={{
                fontFamily: "'Noto Serif Tamil', serif",
                fontSize: 13,
                color: '#FFA07A',
                letterSpacing: '0.2em',
              }}
            >
              {lightbox.caption}
            </div>
            <div
              style={{
                marginTop: 24,
                fontFamily: "'Cormorant Garamond', serif",
                fontSize: 12,
                color: 'rgba(255,215,0,0.4)',
                letterSpacing: '0.3em',
              }}
            >
              CLICK ANYWHERE TO CLOSE
            </div>
          </div>
        </div>
      )}

      <style>{`
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
        @keyframes scaleIn { from { transform: scale(0.85); opacity: 0; } to { transform: scale(1); opacity: 1; } }
      `}</style>
    </section>
  );
};

function getColor(colorClass: string): string {
  const map: { [key: string]: string } = {
    'from-rose-900 to-red-950': 'linear-gradient(145deg, #4a0d1a, #2d0510)',
    'from-emerald-900 to-green-950': 'linear-gradient(145deg, #064a25, #022d10)',
    'from-yellow-800 to-amber-950': 'linear-gradient(145deg, #4a3006, #2d1a02)',
    'from-orange-900 to-red-950': 'linear-gradient(145deg, #4a1e06, #2d0a02)',
    'from-pink-900 to-rose-950': 'linear-gradient(145deg, #4a0d25, #2d0515)',
  };
  return map[colorClass] || 'linear-gradient(145deg, #4a0d1a, #2d0510)';
}

export default PhotoGallery;
